"use client";

import { useEffect } from "react";
import { motion } from "framer-motion";
import Image from "next/image";


interface LogoEmergenceProps {
    onComplete: () => void;
}

const TORA_LOGO_B64 = "data:image/png;base64,";

export function LogoEmergence({ onComplete }: LogoEmergenceProps) {
    useEffect(() => {
        const timer = setTimeout(onComplete, 1500);
        return () => clearTimeout(timer);
    }, [onComplete]);

    return (
        <div className="flex flex-col items-center justify-center min-h-screen relative z-10">
            <motion.div
                initial={{ opacity: 0, scale: 0.95, filter: "blur(10px)" }}
                animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
                transition={{ duration: 1.5, ease: "easeOut" }}
                className="mb-8 relative"
            >
                <div className="w-48 md:w-64 relative z-10">
                    <img src={TORA_LOGO_B64} alt="TORA" className="w-full h-auto" />
                </div>
            </motion.div>

            <motion.p
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 1, delay: 1, ease: "easeOut" }}
                className="text-base md:text-lg font-orbitron tracking-[0.2em] text-white/60 uppercase text-center"
            >
                Where the music industry connects.
            </motion.p>
        </div>
    );
}
